import vex
from smolagents import Agent

claims_agent = Agent(tools=[medical_parser, coverage_checker])

@vex.verify(policies=["claims-explainability", "no-protected-class-bias", "error-boundary"])
def process_claim(claim_data):
    steps = claims_agent.run(f"Evaluate claim: {claim_data}")
    return vex.approve(steps)  # Blocks if reasoning chain fails audit

outcome = process_claim("Injury claim with CPT code 99213, policy #ABC123")
if outcome:
    print('Claim approved with explanation:', outcome.explanation)
